auto_browse <- function(.f) {
  if (is_primitive(.f)) {
    cli::cli_abort(
      "{.arg .f} must not be a primitive function.",
      arg = ".f"
    )
  }

  function(...) {
    withCallingHandlers(
      .f(...),
      error = function(e) {
        # 1: h(simpleError(msg, call))
        # 2: .handleSimpleError(function (e)  <...>
        # 3: stop(...)
        frame <- sys.frame(4)
        browse_in_frame(frame)
      },
      warning = function(e) {
        if (getOption("warn") >= 2) {
          frame <- sys.frame(7)
          browse_in_frame(frame)
        }
      }
    )
  }
}
